import{_ as a,o as t,c as p,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"权力鞭舞","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/权力鞭舞.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/权力鞭舞.md"}'),s={name:"4.资源分区/6.技艺及称号/武技类/白刃类/权力鞭舞.md"};function o(d,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"权力鞭舞",tabindex:"-1"},[b("权力鞭舞 "),r("a",{class:"header-anchor",href:"#权力鞭舞","aria-label":'Permalink to "权力鞭舞"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风021")])])],-1),n('<h1 id="权力鞭舞-1" tabindex="-1">权力鞭舞 <a class="header-anchor" href="#权力鞭舞-1" aria-label="Permalink to &quot;权力鞭舞&quot;">​</a></h1><p>权力鞭舞<br> 前提：使用鞭子类型武器<br> 鞭子是一种杀伤力较弱且击打时的痛感较强的武器，历史悠久，其形态和用途随着时间和文化的变迁而发生了多样化的发展。鞭子曾被广泛用作惩罚手段，也是是权力和控制的象征。所以<br> 现在就会动鞭子让他们臣服吧。</p><p>低下头颅<br> D+500<br> 外表的强大没有意义，高傲的狮子甚至巨像也只能臣服于驯兽师的鞭挞。<br> 挥舞你的鞭子，怎样的敌人也只能任你摆布，使用鞭类武器进行拖拽或擒抱时，你无视体积带来的优势与劣势。</p><p>展示主权<br> D+500<br> 一轮一次，使用迅捷动作轻轻拉动鞭子，或是用其他方式表达侵略的意图，令你本轮中下一次使用鞭类武器进行的攻击检定额外具有5破甲，且在此次攻击结算后，可以立刻使用鞭子对攻击目标之一进行一次拖拽。<br> 升级：10XP，提升为C级技艺，获得差值属性点，效果改为：使用迅捷动作轻轻拉动鞭子，或是用其他方式表达侵略的意图，令你本轮中下一次使用鞭类武器进行的攻击检定获得2增强加值，具有【碾压】特性，且在此次攻击结算后，可以立刻使用鞭子对攻击目标之一进行一次拖拽。</p><p>带来痛苦或欢愉<br> C+1000<br> 最大限度地发挥鞭类武器的特质，在使用鞭类武器进行攻击时，你可以令此次攻击不造成任何伤害，而是通过你的手法，改为造成等量的 创伤来源剧痛点数/影响心灵来源的迷情点数/变形来源的纠缠点数，分别表现为，如同驱策牛马一般着力鞭策产生痛苦/如同女王一般通过控制力度的鞭打引发对方的内啡肽分泌产生愉悦与迷恋/使用鞭子缠绕对方的身体来影响行动，在使用鞭类武器进行攻击时三选一。</p><p>荆棘之舞<br> C+1000<br> 挥舞手中的鞭子，宣布这里归我所有。这是一个攻击技艺，挥舞鞭子对触及范围内的所有敌人进行一次攻击，所有敌人使用反射检定豁免。<br> 22XP：提升为B级技艺，获得差值属性点，这次攻击具有【接触攻击】特性，且直到你的下回合开始，对于敌人来说你的触及范围视为具有B级困难地形。</p><p>鞭长亦可及<br> B+1000<br> 现在你已经对于使用鞭子完全得心应手，每回合获得获得4点AP，但只能用于使用鞭子进行的攻击动作，特殊的，如果你因为某种能力能借助鞭类武器或绳子进行移动，则也可以将AP用于相关移动动作。你知晓如何完全伸长鞭子，甚至是利用韧性在挥舞时进一步延长鞭子的长度，根据你手中鞭子的等级（D1C2B3A4S5），其触及范围提升等级*60M。</p><p>单抽<br> D+500<br> 每场景仅一次，你可以使用移动动作挥舞手中的鞭类武器对触及范围内的一名友方进行鞭策，令其在本场景中获得至多为你的鞭类武器攻击检定主属性一半的天生防御，但其需要进行一次强韧豁免或意志豁免，DC为其获得天生防御的数值，失败则承受差值不可豁免的剧痛点数。<br> 可差价升级为：十连抽</p><p>十连抽<br> C+1250<br> 每场景仅一次，你可以使用移动动作挥舞手中的鞭类武器对触及范围内的一名友方进行鞭策，令其在本场景中获得至多为你的鞭类武器攻击检定主属性一半的天生防御与至多为你的鞭类武器攻击检定主属性一半的攻击检定上的士气加值。但其需要进行一次强韧豁免或意志豁免，DC为其获得天生防御+士气加值的数值。失败则承受差值不可豁免的剧痛点数。<br> 可差价升级为：一百抽</p><p>一百抽<br> B+3750<br> 每场景仅一次，你可以使用移动动作挥舞手中的鞭类武器对触及范围内的一名友方进行鞭策，令其在本场景中获得至多为你的鞭类武器攻击检定主属性的天生防御与至多为你的鞭类武器攻击检定主属性的攻击检定上的士气加值。但其需要进行一次强韧豁免或意志豁免，DC为其获得天生防御+士气加值的数值。失败则承受差值不可豁免的剧痛点数，但现在技法熟练的你也可以改为令其承受等量不可豁免的对你的迷情点数。</p><p>农场主<br> 1500<br> 在使用十连抽或一百抽时，你可以将提供的加值分散交给触及范围内的所有友方，但总上限不变，例如你的主属性为16，十连抽可以提供8点天生防御与8点攻击检定的士气加值，你可以将这些加值自由分配给友方，例如A获得3天生防御与7士气加值，B获得5天生防御与1士气加值，此时他们需要根据自己获得的天生防御与士气加值之和作为DC进行强韧或意志豁免。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const C=a(s,[["render",o]]);export{f as __pageData,C as default};
